st_re = re.compile(r'^(?:\(cid:131\)\s*)?(?:Begin Construction|Start|Construction Start|Begin|Kickoff)\s*:\s*(.+)$', re.I)
alt_st_re = re.compile(r'^(?:\(cid:131\)\s*)?(?:Complete Design|Advertise|Final Design|Preliminary Design)\s*:\s*(.+)$', re.I)

